import numpy as np

# Common backbone idea: Modify edge distances based on their usage in local optimal routes to encourage exploration of alternative paths.

# {Identify the edges that are used more than a standard deviation above the average usage and decrease their distances to reduce their influence, encouraging the formation of shorter routes.}
def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    decreased_distance_factor = 0.9  # Factor to decrease the distance of highly used edges
    avg_usage = np.mean(edge_n_used)
    std_dev_usage = np.std(edge_n_used)
    usage_threshold = avg_usage + std_dev_usage

    updated_edge_distance = np.copy(edge_distance)

    for tour in local_opt_tours:
        for i in range(len(tour) - 1):
            u, v = tour[i], tour[i + 1]
            if edge_n_used[u][v] > usage_threshold:
                updated_edge_distance[u][v] *= decreased_distance_factor
                updated_edge_distance[v][u] *= decreased_distance_factor

    return updated_edge_distance
